// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";

contract MyERC721Token is ERC721URIStorage, ReentrancyGuard, Ownable {
    using ECDSA for bytes32;

    enum State { OpenForSale, MintingInProgress, SaleEnded }
    State public state = State.OpenForSale;

    string[] private _tokenURISuffixes;
    mapping(bytes32 => bool) private _usedSessions;
    uint256 public constant MAX_UNITS = 100; // Maximum number of tokens to be minted
    uint256 private _totalSupply = 0;
    address private _signerAddress;

    event Mint(address indexed to, uint256 tokenId);
    event StateChanged(State newState);
    event Withdrawn(address indexed sender, uint256 amount);

    modifier onlyWhileState(State _state) {
        require(state == _state, "Invalid state");
        _;
    }

    modifier onlyOwnerOrEOA() {
        require(msg.sender == tx.origin || msg.sender == owner(), "Only EOA or Owner");
        _;
    }

    constructor(string[] memory tokenURISuffixes, address signerAddress)
        ERC721("MyERC721Token", "META")
    {
        _tokenURISuffixes = tokenURISuffixes;
        _signerAddress = signerAddress;
    }

    function mintTokens(bytes32 sessionID, bytes memory signature) external onlyWhileState(State.OpenForSale) {
        require(!_usedSessions[sessionID], "Session already used");
        require(_totalSupply < MAX_UNITS, "Max units reached");

        bytes32 messageHash = keccak256(abi.encodePacked(address(this), msg.sender, sessionID));
        require(messageHash.toEthSignedMessageHash().recover(signature) == _signerAddress, "Invalid signature");

        _usedSessions[sessionID] = true;
        uint256 tokenId = _totalSupply + 1;
        _totalSupply = tokenId;
        _safeMint(msg.sender, tokenId);
        _setTokenURI(tokenId, string(abi.encodePacked("https://example.com/", _tokenURISuffixes[tokenId % _tokenURISuffixes.length]));
        emit Mint(msg.sender, tokenId);
    }

    function setTokenURISuffixes(string[] memory newSuffixes) external onlyOwner onlyWhileState(State.MintingInProgress) {
        _tokenURISuffixes = newSuffixes;
    }

    function setState(State newState) external onlyOwnerOrEOA {
        if (newState == State.MintingInProgress && state != State.OpenForSale) revert("Invalid transition");
        if (newState == State.SaleEnded && state != State.MintingInProgress) revert("Invalid transition");
        state = newState;
        emit StateChanged(newState);
    }

    function withdrawAll() external nonReentrant {
        uint256 balance = address(this).balance;
        balance = 0; // Set balance to zero before transfer
        payable(msg.sender).transfer(balance);
        emit Withdrawn(msg.sender, balance);
    }

    receive() external payable {}
}
